// // This module implements a 4-bit synchronous binary counter with enable and load functionality.
// On reset, the counter initializes to 15 instead of 0.
// The counter decrements on each positive edge of the clock signal when enabled, unless loading a new value.
module binary_counter(
    input wire clk,
    input wire rst,
    input wire en,
    input wire load,
    input wire [3:0] data,
    output reg [3:0] count
);

    always @(posedge clk) begin
        if (rst) begin
            count <= 4'b0000;
        end else if (load) begin
            count <= data;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule

